# Generated by Claude on 2026-05-13 for task 02. Prompt: thesis_prompts/02_dynamic_discovery_pick_place.md
"""
Dynamic FR3 pick-and-place controller.

No object names or coordinates are hardcoded. On the first physics tick the
controller scans the USD stage and infers:

  * the robot's base position (any articulation root under /World)
  * the set of "table surfaces" - static colliders whose top face is above the
    ground plane (large, axis-aligned, no rigid body)
  * the set of "movable cubes"  - rigid bodies that are NOT the robot itself
    and that are resting on top of some table
  * the closest movable cube to the robot's base (target to pick)
  * the table farthest from that cube whose top is reachable
    (target surface to place on, excluding the table the cube currently sits on)

It then drives the FR3 through approach -> grasp -> lift -> traverse -> place
-> retreat using RMPflow, exactly like the previous controller but with all
targets computed at runtime.
"""

from __future__ import annotations

import math
import numpy as np
from pxr import Gf, Usd, UsdGeom, UsdPhysics


# --------------------------------------------------------------------------
# Tunables that are about controller behaviour, not scene geometry
# --------------------------------------------------------------------------
APPROACH_HEIGHT = 0.15        # m above pick/place target for safe waypoint
GRIPPER_OPEN    = 0.04        # m per finger
GRIPPER_CLOSED  = 0.005       # m per finger, squeeze
POS_TOL         = 0.02        # m, "reached" tolerance for EE convergence
TIMEOUT_FRAMES  = 240         # bail out of a phase after this many frames

PHASE_MIN_FRAMES = {"grasp": 60, "release": 30}
DEFAULT_MIN_FRAMES = 1


# --------------------------------------------------------------------------
# Scene discovery
# --------------------------------------------------------------------------
def _world_position(prim: Usd.Prim) -> np.ndarray:
    xf = UsdGeom.Xformable(prim)
    m = xf.ComputeLocalToWorldTransform(Usd.TimeCode.Default())
    return np.array([m[3][0], m[3][1], m[3][2]])


def _world_aabb(prim: Usd.Prim):
    cache = UsdGeom.BBoxCache(Usd.TimeCode.Default(), [UsdGeom.Tokens.default_])
    bb = cache.ComputeWorldBound(prim).ComputeAlignedRange()
    if bb.IsEmpty():
        return None
    lo, hi = bb.GetMin(), bb.GetMax()
    return np.array([lo[0], lo[1], lo[2]]), np.array([hi[0], hi[1], hi[2]])


def _has_rigid_body(prim: Usd.Prim) -> bool:
    if not prim.HasAPI(UsdPhysics.RigidBodyAPI):
        return False
    rb = UsdPhysics.RigidBodyAPI(prim)
    enabled_attr = rb.GetRigidBodyEnabledAttr()
    if enabled_attr and enabled_attr.HasAuthoredValue() and not enabled_attr.Get():
        return False
    kinematic_attr = rb.GetKinematicEnabledAttr()
    if kinematic_attr and kinematic_attr.Get():
        return False
    return True


def _has_collision(prim): return prim.HasAPI(UsdPhysics.CollisionAPI)
def _is_articulation_root(prim): return prim.HasAPI(UsdPhysics.ArticulationRootAPI)


def _find_robot_base(stage):
    for prim in stage.Traverse():
        if not prim.GetPath().pathString.startswith("/World/"):
            continue
        if _is_articulation_root(prim):
            return prim.GetPath().pathString, _world_position(prim)
    return None


def _discover_tables(stage):
    tables = []
    for prim in stage.GetPrimAtPath("/World").GetChildren():
        path = prim.GetPath().pathString
        if prim.GetTypeName() == "Plane":
            continue
        if not _has_collision(prim):
            continue
        if _has_rigid_body(prim):
            continue
        if _is_articulation_root(prim):
            continue
        bb = _world_aabb(prim)
        if bb is None:
            continue
        lo, hi = bb
        if hi[2] < 0.1:
            continue
        tables.append({
            "path": path,
            "center": _world_position(prim),
            "bbox_min": lo,
            "bbox_max": hi,
            "top_z": float(hi[2]),
            "footprint_center": np.array([(lo[0] + hi[0]) / 2, (lo[1] + hi[1]) / 2]),
        })
    return tables


def _which_table_supports(pos, tables):
    best, best_gap = None, float("inf")
    for t in tables:
        lo, hi = t["bbox_min"], t["bbox_max"]
        if not (lo[0] <= pos[0] <= hi[0] and lo[1] <= pos[1] <= hi[1]):
            continue
        gap = pos[2] - t["top_z"]
        if gap < -0.02 or gap > 0.20:
            continue
        if abs(gap) < abs(best_gap):
            best, best_gap = t, gap
    return best


def _discover_movable_cubes(stage, robot_path, tables):
    cubes = []
    for prim in stage.Traverse():
        path = prim.GetPath().pathString
        if path.startswith(robot_path + "/") or path == robot_path:
            continue
        if not _has_rigid_body(prim):
            continue
        pos = _world_position(prim)
        bb = _world_aabb(prim)
        if bb is None:
            continue
        lo, hi = bb
        size = hi - lo
        support = _which_table_supports(pos, tables)
        if support is None:
            continue
        cubes.append({
            "path": path, "position": pos, "size": size,
            "half_height": float(size[2] / 2),
            "on_table": support["path"],
        })
    return cubes


def _pick_target_cube(cubes, robot_xy):
    if not cubes:
        return None
    return min(cubes, key=lambda c: float(np.linalg.norm(c["position"][:2] - robot_xy)))


def _pick_placement_table(tables, cube, robot_xy, reach_radius=0.85):
    cube_xy = cube["position"][:2]
    candidates = []
    for t in tables:
        if t["path"] == cube["on_table"]:
            continue
        if float(np.linalg.norm(t["footprint_center"] - robot_xy)) > reach_radius:
            continue
        candidates.append(t)
    if not candidates:
        return None
    return max(candidates, key=lambda t: float(np.linalg.norm(t["footprint_center"] - cube_xy)))


# --------------------------------------------------------------------------
# Controller state
# --------------------------------------------------------------------------
_STATE = {
    "discovered": False, "initialized": False,
    "phase": 0, "phase_frames": 0,
    "robot": None, "rmpflow": None, "art_rmpflow": None, "gripper": None,
    "phases": [], "robot_path": None, "ee_prim": None,
    "target_cube": None, "place_table": None,
}


def _build_phase_plan(cube, place_table):
    pick_xyz = cube["position"].copy()
    place_xy = place_table["footprint_center"]
    place_z = place_table["top_z"] + cube["half_height"]
    place_xyz = np.array([place_xy[0], place_xy[1], place_z])
    up = np.array([0.0, 0.0, APPROACH_HEIGHT])
    return [
        ("approach_pick",  pick_xyz + up,  GRIPPER_OPEN),
        ("descend_pick",   pick_xyz,       GRIPPER_OPEN),
        ("grasp",          pick_xyz,       GRIPPER_CLOSED),
        ("lift",           pick_xyz + up,  GRIPPER_CLOSED),
        ("approach_place", place_xyz + up, GRIPPER_CLOSED),
        ("descend_place",  place_xyz,      GRIPPER_CLOSED),
        ("release",        place_xyz,      GRIPPER_OPEN),
        ("retreat",        place_xyz + up, GRIPPER_OPEN),
    ]


def _discover(stage):
    robot = _find_robot_base(stage)
    if robot is None:
        raise RuntimeError("no articulation root found under /World")
    robot_path, robot_pos = robot
    robot_xy = robot_pos[:2]

    tables = _discover_tables(stage)
    if len(tables) < 2:
        raise RuntimeError(f"need >=2 tables, found {len(tables)}")
    cubes = _discover_movable_cubes(stage, robot_path, tables)
    if not cubes:
        raise RuntimeError("no movable cubes resting on any table")

    target = _pick_target_cube(cubes, robot_xy)
    place = _pick_placement_table(tables, target, robot_xy)
    if place is None:
        raise RuntimeError("no reachable placement table found")

    print(f"[dyn_pp] robot         = {robot_path} @ {robot_pos.round(3)}")
    print(f"[dyn_pp] tables found  = {len(tables)}")
    for t in tables:
        print(f"[dyn_pp]   {t['path']:<25} center={t['footprint_center'].round(3)} top_z={t['top_z']:.3f}")
    print(f"[dyn_pp] cubes found   = {len(cubes)}")
    for c in cubes:
        d = float(np.linalg.norm(c['position'][:2] - robot_xy))
        print(f"[dyn_pp]   {c['path']:<25} pos={c['position'].round(3)} on={c['on_table']} d_robot={d:.3f}")
    print(f"[dyn_pp] selected cube = {target['path']}  (closest to robot)")
    print(f"[dyn_pp] place table   = {place['path']}  (farthest reachable)")

    _STATE["robot_path"] = robot_path
    _STATE["target_cube"] = target
    _STATE["place_table"] = place
    _STATE["phases"] = _build_phase_plan(target, place)
    _STATE["discovered"] = True


def _initialize_motion(stage):
    from isaacsim.core.prims import SingleArticulation
    from isaacsim.robot_motion.motion_generation import (
        RmpFlow, ArticulationMotionPolicy, interface_config_loader,
    )
    from isaacsim.robot.manipulators.grippers import ParallelGripper

    robot_path = _STATE["robot_path"]
    robot = SingleArticulation(prim_path=robot_path, name="robot")
    robot.initialize()

    joint_prefix = robot.dof_names[0].split("_")[0]
    preset = {"fr3": "FR3", "panda": "Franka"}.get(joint_prefix)
    if preset is None:
        raise RuntimeError(f"no RMPflow preset known for joint prefix {joint_prefix!r}")

    rmp_cfg = interface_config_loader.load_supported_motion_policy_config(preset, "RMPflow")
    rmpflow = RmpFlow(**rmp_cfg)
    art_rmpflow = ArticulationMotionPolicy(
        robot_articulation=robot, motion_policy=rmpflow,
        default_physics_dt=1.0 / 60.0,
    )

    hand_path = None
    finger_joints = []
    for prim in stage.Traverse():
        p = prim.GetPath().pathString
        if not p.startswith(robot_path + "/"):
            continue
        name = prim.GetName().lower()
        if hand_path is None and name.endswith("_hand"):
            hand_path = p
        if "finger_joint" in name and prim.GetTypeName() == "PhysicsPrismaticJoint":
            finger_joints.append(prim.GetName())
    if hand_path is None or len(finger_joints) < 2:
        raise RuntimeError(f"could not infer gripper layout")
    finger_joints = sorted(finger_joints)[:2]

    tcp_candidates = [p.GetPath().pathString for p in stage.Traverse()
                      if p.GetPath().pathString.startswith(hand_path + "/")
                      and p.GetName().endswith("_tcp")]
    ee_prim = tcp_candidates[0] if tcp_candidates else hand_path

    gripper = ParallelGripper(
        end_effector_prim_path=hand_path,
        joint_prim_names=finger_joints,
        joint_opened_positions=np.array([GRIPPER_OPEN, GRIPPER_OPEN]),
        joint_closed_positions=np.array([GRIPPER_CLOSED, GRIPPER_CLOSED]),
        action_deltas=np.array([0.01, 0.01]),
    )
    gripper.initialize(
        articulation_apply_action_func=robot.apply_action,
        get_joint_positions_func=robot.get_joint_positions,
        set_joint_positions_func=robot.set_joint_positions,
        dof_names=robot.dof_names,
    )

    _STATE["robot"] = robot
    _STATE["rmpflow"] = rmpflow
    _STATE["art_rmpflow"] = art_rmpflow
    _STATE["gripper"] = gripper
    _STATE["ee_prim"] = ee_prim
    _STATE["initialized"] = True
    print(f"[dyn_pp] motion initialised: preset={preset} hand={hand_path} "
          f"ee={ee_prim} fingers={finger_joints}")


def _ee_position(stage):
    prim = stage.GetPrimAtPath(_STATE["ee_prim"])
    if not prim or not prim.IsValid():
        return None
    return _world_position(prim)


def _drive_current_phase(stage):
    idx = _STATE["phase"]
    if idx >= len(_STATE["phases"]):
        return
    name, target_xyz, gripper_target = _STATE["phases"][idx]
    target_orient = np.array([0.0, 1.0, 0.0, 0.0])
    _STATE["rmpflow"].set_end_effector_target(
        target_position=target_xyz, target_orientation=target_orient
    )
    _STATE["rmpflow"].update_world()
    action = _STATE["art_rmpflow"].get_next_articulation_action()
    _STATE["robot"].apply_action(action)
    finger_action = _STATE["gripper"].forward(
        action="close" if gripper_target < GRIPPER_OPEN * 0.5 else "open"
    )
    if finger_action is not None:
        _STATE["robot"].apply_action(finger_action)


def _advance_phase_if_done(stage):
    idx = _STATE["phase"]
    if idx >= len(_STATE["phases"]):
        return
    name, target_xyz, _ = _STATE["phases"][idx]
    min_frames = PHASE_MIN_FRAMES.get(name, DEFAULT_MIN_FRAMES)
    if _STATE["phase_frames"] < min_frames:
        return
    ee = _ee_position(stage)
    if ee is None:
        return
    err = float(np.linalg.norm(ee - target_xyz))
    if err < POS_TOL or _STATE["phase_frames"] > TIMEOUT_FRAMES:
        print(f"[dyn_pp] phase '{name}' done (err={err:.3f}m, "
              f"frames={_STATE['phase_frames']})")
        _STATE["phase"] += 1
        _STATE["phase_frames"] = 0
        if _STATE["phase"] >= len(_STATE["phases"]):
            print("[dyn_pp] all phases complete")


def step():
    import omni.usd
    stage = omni.usd.get_context().get_stage()
    if stage is None:
        return
    if not _STATE["discovered"]:
        try:
            _discover(stage)
        except Exception as e:
            print(f"[dyn_pp] discovery deferred: {e}")
            return
    if not _STATE["initialized"]:
        try:
            _initialize_motion(stage)
        except Exception as e:
            print(f"[dyn_pp] motion init deferred: {e}")
            return
    _drive_current_phase(stage)
    _STATE["phase_frames"] += 1
    _advance_phase_if_done(stage)


def setup(db):
    db.log_info("[dyn_pp] ScriptNode setup")
    _STATE["discovered"] = False
    _STATE["initialized"] = False
    _STATE["phase"] = 0
    _STATE["phase_frames"] = 0


def compute(db):
    try:
        step()
    except Exception as e:
        db.log_error(f"[dyn_pp] step() raised: {e}")
        return False
    return True


def cleanup(db):
    db.log_info("[dyn_pp] ScriptNode cleanup")
    for k in ("robot", "rmpflow", "art_rmpflow", "gripper",
              "target_cube", "place_table"):
        _STATE[k] = None
    _STATE["phases"] = []
    _STATE["discovered"] = False
    _STATE["initialized"] = False
